ON CONFLICT (sku) DO NOTHING;

-- Inventory for all new products across warehouses
-- Using a pattern: blr-01 gets most stock, others get less
SELECT p.id, w.id,
  CASE w.code
    WHEN 'blr-01' THEN (RANDOM() * 20 + 5)::int
    WHEN 'del-01' THEN (RANDOM() * 15 + 3)::int
    WHEN 'mum-01' THEN (RANDOM() * 10 + 2)::int
    WHEN 'hyd-01' THEN (RANDOM() * 8 + 1)::int
  END
FROM public.products p
CROSS JOIN public.warehouses w
WHERE p.sku NOT IN (
  'ALO-MUG-01','ALO-CHA-01','ALO-LMP-01','ALO-RUG-01','ALO-VAS-01','ALO-BLK-01'
)
AND NOT EXISTS (
  SELECT 1 FROM public.inventory i
  WHERE i.product_id = p.id AND i.warehouse_id = w.id
)
ON CONFLICT (product_id, warehouse_id) DO NOTHING;
